import * as React from 'react';
import { createComponent } from '../create-component.js';
import Component from '../../components/theme-provider/src/theme-provider.component.js';
const tagName = 'made-theme-provider';
Component.define(tagName);
/**
 * @summary Applies a Made theme by using CSS custom properties to set styles on all components in its scope.
 * @documentation '../../components/theme-provider/stories/theme-provider.mdx'
 *
 * @fires mde-change {CustomEvent} - Emitted when the theme changes.
 * @fires mde-error {CustomEvent} - Emitted when the theme doesn't load.
 *
 * @slot - The default slot.
 */
const reactWrapper = createComponent({
    tagName,
    elementClass: Component,
    react: React,
    events: {
        onMdeChange: 'mde-change',
        onMdeError: 'mde-error'
    },
    displayName: 'MadeThemeProvider'
});
export default reactWrapper;
